// Pseudo: sketch of the per-entry state machine in awk (for illustration)
// not a real runnable snippet
BEGIN{in_entry=0; count=0}
$0 ~ /^\d{4}-/ || /"ts":/ {if (in_entry) print count; in_entry=1; count=0}
{if ($0 ~ /LEVEL:/ && $0 ~ /(ERROR|CRITICAL|FATAL)/) count++}
END{if (in_entry) print count}
