// Fingerprint function for deduplication
function fingerprint(hour, message) {
  const normalized = (message || '').toLowerCase().trim();
  const hash = require('crypto').createHash('sha256');
  hash.update(`${hour}:${normalized}`);
  return hash.digest('hex');
}

// Checkpoint persistence
function saveCheckpoint(checkpoint) {
  const tempPath = '/tmp/checkpoint.json';
  fs.writeFileSync(tempPath, JSON.stringify(checkpoint));
  fs.renameSync(tempPath, '/path/to/checkpoints.json');
}
```"

