    }
    /^\{/ {
      if (match($0, /"ts":"([^"]+)"/, t) && match($0, /"lvl":"([^"]+)"/, l)) {
        hour = substr(t[1],1,13)
        counts[hour,l[1]]++
      }
    }
    END {
      for (i=0;i<24;i++) {
        h = strftime("%Y-%m-%d %H", systime() - i*3600)
        printf "%s: INFO=%d WARN=%d ERROR=%d\n", h, counts[h,"INFO"]+0, counts[h,"WARN"]+0, counts[h,"ERROR"]+0
