#!/usr/bin/env bash
cutoff=$(date -d '6 hours ago' '+%Y-%m-%d %H:%M:%S')
zcat /logs/app/**/*.log.gz /logs/app/**/*.log 2>/dev/null | awk -v c="$cutoff" '
  function hour(ts){ return substr(ts,1,13) }
  {
    if($0 ~ /"ts":/) { match($0, /"ts":"([^\"]+)"/, m); ts=m[1]; match($0, /"src":"([^\"]+)"/, s); ip=s[1] }
