for host in $(awk -F'[/=]' '/^\/(logs|var)\/log\// && !/^#/ {print $3}' /etc/hosts 2>/dev/null | sort -u); do
  users=$(find "/logs" -name '*.log*' -mmin -30 2>/dev/null | \
    xargs -I{} sh -c 'zcat -f "{}" 2>/dev/null' | \
    awk -v host="$host" '
      BEGIN {now=systime(); cutoff=now-1800}
      /^[[:space:]]/ {next}
      /^"?[0-9]{4}-[0-9]{2}-[0-9]{2} [0-9]{2}:[0-9]{2}:[0-9]{2}/ {
        gsub(/[\[\]:]/, "", $1" "$2)
        cmd="date -d \""$1" "$2"\" +%s 2>/dev/null || date -d 0 +%s"
        cmd | getline ts; close(cmd)
        if (ts >= cutoff) {
          if ($0 ~ /ERROR|WARN/) {
            for (i=1; i<=NF; i++) {
              if ($i ~ /^user[=:]/) {
                gsub(/[,:"\047]/, "", $(i+1))
                print tolower($(i+1))
              }
            }
          }
        }
        next
      }
      /^"?\{/ {
        if (match($0, /"ts"[[:space:]]*:[[:space:]]*"([^"]+)"/, t)) {
          cmd="date -d \""t[1]"\" +%s 2>/dev/null || date -d 0 +%s"
          cmd | getline ts; close(cmd)
          if (ts >= cutoff && match($0, /"user"[[:space:]]*:[[:space:]]*"([^"]+)"/, u)) {
            print tolower(u[1])
          }
        }
        next
      }
    ' | sort -u | wc -l)
  echo "$host: $users unique users"
done
```

## Why This Is Asked

This question tests the ability to build a real-world, single-line log analytics pipeline that handles multiple formats, gzipped archives, per-service aggregation, and a 30-minute sliding window.

## Key Concepts

- Streaming text processing
- Mixed log formats (CSV and JSON)
- Time bucketing with epoch seconds
- Robust file handling (gzipped and potentially unreadable files)
- Service-based aggregation

## Code Example

```bash
find /var/log/app-*/events -type f \( -name "*.log" -o -name "*.log.gz" \) -print0 | \
while IFS= read -r -d '' f; do
  if [[ "$f" == *.gz ]]; then zcat "$f" || true; else cat "$f" || true; fi
done | \
awk -v window=1800 -v now="$(date +%s)" '
{
  # Extract service from path
  match($0, /\/events\/([^\/]+)\//, arr); service = arr[1]
  if (!service) next

  # Parse CSV or JSON timestamp
  if ($0 ~ /^{/) {
    # JSON format
    gsub(/[{}",]/, "")
    split($0, parts, /[=:]/)
    for (i in parts) {
      if (parts[i] == "ts") ts = parts[i+1]
      if (parts[i] == "sev") sev = parts[i+1]
    }
  } else {
    # CSV format
    split($0, parts, ",")
    ts = parts[1]; sev = parts[2]
  }

  # Filter for ERROR severity within time window
  if (sev == "ERROR") {
    # Convert timestamp to epoch seconds
    if (ts ~ "-") {
      cmd = "date -d \"" ts "\" +%s"
      cmd | getline epoch; close(cmd)
    } else epoch = ts

    if (epoch >= now - window) {
      bucket = int(epoch / 60) * 60
      errors[service, bucket]++
    }
  }
}
END {
  for (key in errors) {
    split(key, arr, SUBSEP)
    printf "%s: %.2f errors/min\n", arr[1], errors[key] / 1
  }
}'
```

This pipeline handles mixed formats, gzipped archives, unreadable files gracefully, and provides per-service ERROR event rates over the specified time window.

