find /logs -name 'service-*/[0-9]*.log*' -type f 2>/dev/null | \
while IFS= read -r f; do \
  if [[ $f == *.gz ]]; then \
    zcat "$f" 2>/dev/null || continue; \
  else \
    cat "$f" 2>/dev/null || continue; \
  fi; \
done | awk '
BEGIN { 
  "date +%s" | getline now; 
  cutoff = now - 3600;
}
{
  # Parse ISO timestamp format
  if (match($0, /^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}/)) {
    ts = substr($0, RSTART, RLENGTH);
    cmd = "date -d \"" ts "\" +%s";
    cmd | getline epoch;
    close(cmd);
    if (epoch >= cutoff && $2 == "ERROR:") {
      service = FILENAME;
      gsub(/.*\//, "", service);
      gsub(//.*/, "", service);
      msg = substr($0, index($0, "ERROR:") + 6);
      count[service "|" msg]++;
    }
  }
  # Parse JSON format
  else if ($0 ~ /^{/) {
    # Extract ts, lvl, msg from JSON
    if (match($0, /"ts"[[:space:]]*:[[:space:]]*"[^"]*"/)) {
      json_ts = substr($0, RSTART, RLENGTH);
      gsub(/.*"/, "", json_ts);
      gsub(/".*/, "", json_ts);
      cmd = "date -d \"" json_ts "\" +%s";
      cmd | getline epoch;
      close(cmd);
      if (epoch >= cutoff) {
        if (match($0, /"lvl"[[:space:]]*:[[:space:]]*"ERROR"/)) {
          if (match($0, /"msg"[[:space:]]*:[[:space:]]*"[^"]*"/)) {
            json_msg = substr($0, RSTART, RLENGTH);
            gsub(/.*"/, "", json_msg);
            gsub(/".*/, "", json_msg);
            service = FILENAME;
            gsub(/.*\//, "", service);
            gsub(//.*/, "", service);
            count[service "|" json_msg]++;
          }
        }
      }
    }
  }
}
END {
  # Aggregate counts by service and output top 5 per service
  for (key in count) {
    split(key, parts, "|");
    service = parts[1];
    msg = parts[2];
    service_count[service "|" msg] = count[key];
    services[service] = 1;
  }

  for (svc in services) {
    print "\n=== " svc " ===";
    n = 0;
    for (key in service_count) {
      split(key, parts, "|");
      if (parts[1] == svc) {
        messages[++n] = parts[2];
        values[n] = service_count[key];
      }
    }

    # Simple bubble sort for top 5
    for (i = 1; i <= n; i++) {
      for (j = i + 1; j <= n; j++) {
        if (values[j] > values[i]) {
          temp = values[i]; values[i] = values[j]; values[j] = temp;
          temp = messages[i]; messages[i] = messages[j]; messages[j] = temp;
        }
      }
    }

    for (i = 1; i <= (n < 5 ? n : 5); i++) {
      printf "%d: %s\n", values[i], messages[i];
    }
  }
}'
```

This solution handles mixed log formats, gzip archives, time-based filtering, per-service aggregation, and gracefully skips unreadable files.
